from pydantic import BaseModel, field_validator

# Shared schema — lives in a shared module imported by all agents
class RetrieverOutput(BaseModel):
    chunks: list[str]
    source_urls: list[str]

    @field_validator("chunks")
    @classmethod
    def chunks_not_empty(cls, v):
        if not v:
            raise ValueError("chunks must contain at least one item")
        return v

class WriterInput(BaseModel):
    context: str          # writer expects a joined string, not a list

def retriever_to_writer(output: RetrieverOutput) -> WriterInput:
    """Explicit adapter between agent schemas — no silent type coercion."""
    return WriterInput(context="\n\n".join(output.chunks))

# Usage:
raw = RetrieverOutput(
    chunks=["fact 1", "fact 2"],
    source_urls=["https://example.com"],
)
writer_in = retriever_to_writer(raw)
# writer_in.context == "fact 1\n\nfact 2"

from dataclasses import dataclass
from typing import Optional
import asyncio
from anthropic import AsyncAnthropic

@dataclass
class AgentResult:
    success: bool
    content: str
    error: Optional[str] = None

    @classmethod
    def fallback(cls, error: str) -> "AgentResult":
        return cls(success=False, content="", error=error)

async def retriever_safe(query: str, client: AsyncAnthropic) -> AgentResult:
    try:
        resp = await client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system="Retrieve facts.",
            messages=[{"role": "user", "content": query}],
        )
        return AgentResult(success=True, content=resp.content[0].text)
    except Exception as exc:
        return AgentResult.fallback(str(exc))

async def writer_safe(retrieval: AgentResult, client: AsyncAnthropic) -> AgentResult:
    if not retrieval.success:
        # Degrade gracefully — produce a minimal output acknowledging the gap
        return AgentResult(
            success=True,
            content=f"[Retrieval failed: {retrieval.error}. Writing from general knowledge.]",
        )
    try:
        resp = await client.messages.create(
            model="claude-sonnet-5",
            max_tokens=2048,
            system="Write a report from these facts.",
            messages=[{"role": "user", "content": retrieval.content}],
        )
        return AgentResult(success=True, content=resp.content[0].text)
    except Exception as exc:
        return AgentResult.fallback(str(exc))
